// RemoteOK devuelve array, primer elemento es metadata
const jobs = $input.first().json;
const items = Array.isArray(jobs) ? jobs.slice(1) : [];

return items.map(job => ({
  json: {
    source_slug:    'remoteok',
    external_id:    String(job.id),
    title:          job.position || '',
    company:        job.company  || '',
    description:    job.description || '',
    location:       'Remote',
    modality:       'remote',
    seniority:      inferSeniority(job.position + ' ' + job.description),
    required_skills: (job.tags || []).map(t => t.trim()),
    apply_url:      job.url || `https://remoteok.com/l/${job.id}`,
    posted_at:      job.date ? new Date(job.date).toISOString() : new Date().toISOString(),
    salary_min:     job.salary_min ? parseInt(job.salary_min) : null,
    salary_max:     job.salary_max ? parseInt(job.salary_max) : null,
    salary_currency: 'USD',
    salary_period:  'yearly',
  }
}));

function inferSeniority(text) {
  const t = (text || '').toLowerCase();
  if (/\b(staff|principal)\b/.test(t))     return 'staff';
  if (/\b(lead|tech lead)\b/.test(t))      return 'lead';
  if (/\b(senior|sr\.?)\b/.test(t))        return 'senior';
  if (/\b(mid|middle|pleno)\b/.test(t))    return 'mid';
  if (/\b(junior|jr\.?|entry)\b/.test(t)) return 'junior';
  return 'unknown';
}

