function extractSkills(text) {
  const t = text.toLowerCase();
  const known = ['react', 'react native', 'typescript', 'javascript', 'next.js',
    'graphql', 'node.js', 'redux', 'tailwind', 'css', 'html'];
  return known.filter(s => t.includes(s));
}

const data = $input.first().json;
const jobs = Array.isArray(data) ? data : (data.jobs || []);

return jobs.map(job => ({
  json: {
    source_slug:    'workingnomads',
    external_id:    String(job.id),
    title:          job.title || '',
    company:        job.company || '',
    description:    job.description || '',
    location:       'Remote',
    modality:       'remote',
    seniority:      inferSeniority(job.title || ''),
    required_skills: [],
    apply_url:      job.url || '',
    posted_at:      job.pub_date || new Date().toISOString(),
    salary_min:     null,
    salary_max:     null,
    salary_currency: 'USD',
    salary_period:  'yearly',
  }
}));

function inferSeniority(text) {
  const t = (text || '').toLowerCase();
  if (/\b(senior|sr\.?)\b/.test(t)) return 'senior';
  if (/\b(mid|middle)\b/.test(t))   return 'mid';
  if (/\b(junior|jr\.?)\b/.test(t)) return 'junior';
  return 'unknown';
}

// Perfil de Ramiro (hardcoded para MVP — luego viene de Supabase)
const PROFILE = {
  seniority: 'senior',
  targetRoles: ['Frontend Developer','Senior Frontend Developer','React Developer','React Native Developer','Full Stack Developer'],
  primarySkills: ['React.js','React Native','TypeScript','JavaScript'],
  secondarySkills: ['Redux Toolkit','GraphQL','Material UI','Firebase','Next.js','Tailwind CSS'],
  preferredModality: 'remote',
  location: 'Santa Rosa, La Pampa, Argentina',
  languages: [{ lang: 'Spanish', level: 'native' },{ lang: 'English', level: 'B2' }],
  minScoreThreshold: 60,
  alertScoreThreshold: 75,
};

const job = $input.first().json;

// --- Title match (0-20) ---
function scoreTitle(title, roles) {
  const t = title.toLowerCase();
  for (const r of roles) {
    const rl = r.toLowerCase();
    if (t === rl) return 20;
    if (t.includes(rl) || rl.includes(t)) return 15;
  }
  const words = new Set(t.split(/\s+/));
  const best = roles.reduce((b, r) => {
    const rw = r.toLowerCase().split(/\s+/);
    const overlap = rw.filter(w => words.has(w) && w.length > 2).length;
    return Math.max(b, overlap / rw.length);
  }, 0);
  if (best >= 0.5) return 10;
  if (best > 0) return 5;
  return 0;
}

// --- Skills match (0-35) ---
function normalize(s) { return s.toLowerCase().trim().replace(/[^a-z0-9 .]/g,''); }
function skillsMatch(a, b) {
  const na = normalize(a), nb = normalize(b);
  return na === nb || na.includes(nb) || nb.includes(na);
}
function scoreSkills(required, primary, secondary) {
  if (!required || required.length === 0) return 18;
  const all = [...primary, ...secondary];
  const matched = required.filter(r => all.some(p => skillsMatch(r, p)));
  const missing = required.filter(r => !all.some(p => skillsMatch(r, p)));
  const ratio = matched.length / required.length;
  const bonus = required.some(r => primary.some(p => skillsMatch(r, p))) ? 5 : 0;
  return { score: Math.min(Math.round(35 * ratio) + bonus, 35), matched, missing };
}

// --- Seniority (0-15) ---
const LEVELS = { junior:1, mid:2, senior:3, staff:4, lead:5, unknown:0 };
function scoreSeniority(jobSen, profSen) {
  if (jobSen === 'unknown') return 9;
  const diff = Math.abs((LEVELS[jobSen]||0) - (LEVELS[profSen]||0));
  if (diff === 0) return 15;
  if (diff === 1) return 9;
  if (diff === 2) return 3;
  return 0;
}

// --- Modality (0-15) ---
function scoreModality(jobMod) {
  if (jobMod === 'remote') return 15;
  if (jobMod === 'hybrid') return 10;
  return 0;
}

// --- Location (0-10) ---
function scoreLocation(loc, mod) {
  if (mod === 'remote') return 10;
  const l = (loc||'').toLowerCase();
  if (l.includes('argentina')) return 10;
  if (l.includes('latam') || l.includes('latin america')) return 7;
  return 0;
}

// --- Language (0-5) ---
function scoreLanguage(desc, languages) {
  const d = (desc||'').toLowerCase();
  if (!/english|inglés/.test(d)) return 5;
  const en = languages.find(l => l.lang.toLowerCase() === 'english');
  if (!en) return 0;
  const lvl = { B2:3, C1:4, C2:5, native:6, B1:2, A2:1, A1:0 }[en.level] || 0;
  return lvl >= 3 ? 5 : (lvl === 2 ? 3 : 0);
}

// Calcular
const titleScore    = scoreTitle(job.title, PROFILE.targetRoles);
const skillsResult  = scoreSkills(job.required_skills, PROFILE.primarySkills, PROFILE.secondarySkills);
const skillsScore   = typeof skillsResult === 'number' ? skillsResult : skillsResult.score;
const matched       = typeof skillsResult === 'number' ? [] : skillsResult.matched;
const missing       = typeof skillsResult === 'number' ? [] : skillsResult.missing;
const seniorityScore = scoreSeniority(job.seniority, PROFILE.seniority);
const modalityScore = scoreModality(job.modality);
const locationScore = scoreLocation(job.location, job.modality);
const languageScore = scoreLanguage(job.description, PROFILE.languages);

const total = titleScore + skillsScore + seniorityScore + modalityScore + locationScore + languageScore;

const reasons = [];
if (titleScore >= 15)       reasons.push('Título coincide con tu perfil');
if (matched.length > 0)     reasons.push(`Skills: ${matched.slice(0,4).join(', ')}`);
if (seniorityScore === 15)  reasons.push(`Seniority exacto (${job.seniority})`);
if (modalityScore === 15)   reasons.push('Modalidad remota');
if (languageScore === 5)    reasons.push('Inglés aceptado (B2+)');

const flags = [];
if (!job.salary_min && !job.salary_max)  flags.push('Salario no especificado');
if (job.seniority === 'unknown')         flags.push('Seniority no claro');
if (missing.length > 2)                 flags.push(`Skills faltantes: ${missing.slice(0,3).join(', ')}`);

return [{
  json: {
    ...job,
    match: {
      score: total,
      breakdown: { title: titleScore, skills: skillsScore, seniority: seniorityScore, modality: modalityScore, location: locationScore, language: languageScore },
      match_reasons: reasons,
      flags,
      above_threshold: total >= PROFILE.minScoreThreshold,
      above_alert: total >= PROFILE.alertScoreThreshold,
    }
  }
}];

// Registrar errores sin romper el workflow
const error = $input.first().json;
console.error('Workflow error:', JSON.stringify(error));
return [{ json: { error: true, message: error.message || 'Unknown error', timestamp: new Date().toISOString() } }];
